# Compile-Time Constraint Types in TypeScript

## 1. Type-Safe Route Parameters

```typescript
// ============================================================
// ROUTE PARAMETER EXTRACTION & ENFORCEMENT
// ============================================================

/**
 * Extracts parameter names from a URL template string.
 * "/users/:userId/posts/:postId" → "userId" | "postId"
 */
type ExtractRouteParams<T extends string> =
  // Match segments that start with ":"
  T extends `${infer _Start}:${infer Param}/${infer Rest}`
    ? Param | ExtractRouteParams<Rest>
    : T extends `${infer _Start}:${infer Param}`
      ? Param
      : never;

/**
 * Builds the required params object type from a URL template.
 * "/users/:userId" → { userId: string }
 */
type RouteParams<T extends string> = {
  [K in ExtractRouteParams<T>]: string;
};

/**
 * The Route type couples a path template with its extracted params.
 */
interface Route<T extends string> {
  path: T;
  params: RouteParams<T>;
  // Computed full URL after parameter substitution
  toURL(): string;
}

/**
 * Creates a type-safe route. The params object MUST contain exactly
 * the parameters declared in the URL template — no more, no less.
 */
function createRoute<T extends string>(
  path: T,
  // Enforce EXACT match: params must have all route keys, and
  // no extra keys are allowed via the two-way constraint.
  ...args: ExtractRouteParams<T> extends never
    ? []  // No params needed for paths like "/health"
    : [params: RouteParams<T> & Record<string, string>]
): Route<T> {
  const params = (args[0] ?? {}) as RouteParams<T>;

  return {
    path,
    params,
    toURL(): string {
      let url: string = path;
      for (const [key, value] of Object.entries(params)) {
        url = url.replace(`:${key}`, value);
      }
      return url;
    },
  };
}

// ---------- Compile-time verification tests ----------

// ✅ VALID: params exactly match the template
const userPostRoute = createRoute(
  '/users/:userId/posts/:postId',
  { userId: '123', postId: '456' }
);
//    ^? Route<"/users/:userId/posts/:postId">

console.log(userPostRoute.toURL());
// → "/users/123/posts/456"

// ✅ VALID: single parameter
const userRoute = createRoute('/users/:userId', { userId: '42' });

// ✅ VALID: no parameters required
const healthRoute = createRoute('/health');

// ❌ COMPILE ERROR: 'wrongParam' does not satisfy { userId: string }
// @ts-expect-error
const badRoute1 = createRoute('/users/:userId', { wrongParam: '123' });

// ❌ COMPILE ERROR: missing 'postId'
// @ts-expect-error
const badRoute2 = createRoute('/users/:userId/posts/:postId', { userId: '123' });

// ❌ COMPILE ERROR: missing 'userId' AND 'postId'
// @ts-expect-error
const badRoute3 = createRoute('/users/:userId/posts/:postId', {});


// ---------- Advanced: Strict exact-key enforcement ----------

/**
 * StrictRouteParams rejects objects with EXTRA keys at compile time.
 * This uses the "Exact" type pattern.
 */
type Exact<T, Shape> = T extends Shape
  ? Exclude<keyof T, keyof Shape> extends never
    ? T
    : never
  : never;

function createStrictRoute<
  T extends string,
  P extends RouteParams<T>
>(
  path: T,
  ...args: ExtractRouteParams<T> extends never
    ? []
    : [params: Exact<P, RouteParams<T>>]
): Route<T> {
  const params = (args[0] ?? {}) as RouteParams<T>;
  return {
    path,
    params,
    toURL(): string {
      let url: string = path;
      for (const [key, value] of Object.entries(params)) {
        url = url.replace(`:${key}`, value);
      }
      return url;
    },
  };
}

// ✅ Exact match
const strict1 = createStrictRoute('/api/:version/items/:itemId', {
  version: 'v2',
  itemId: '99',
});

// ❌ COMPILE ERROR: extra key 'bonus' not in template
// @ts-expect-error
const strict2 = createStrictRoute('/api/:version', {
  version: 'v2',
  bonus: 'nope',
});
