## 2. Ordered Builder Pattern

```typescript
// ============================================================
// ORDERED BUILDER WITH PHANTOM TYPE STATE
// ============================================================

/**
 * We model the builder's state as a type-level "checklist."
 * Each step transitions the builder to a new state, and only
 * the correct next method is available.
 *
 * State machine:
 *   NeedName  --setName-->  NeedAge  --setAge-->  Ready  --build-->  Person
 */

interface Person {
  name: string;
  age: number;
}

// ---------- State markers (phantom types) ----------
interface NeedName {
  readonly _brand: 'NeedName';
}
interface NeedAge {
  readonly _brand: 'NeedAge';
}
interface Ready {
  readonly _brand: 'Ready';
}

// ---------- Conditional method interfaces ----------

/**
 * Each interface exposes ONLY the method valid for that state.
 * TypeScript's conditional mapped types make all other methods invisible.
 */
interface BuilderMethods<State> {
  // setName is ONLY available when State is NeedName
  setName: State extends NeedName
    ? (name: string) => Builder<NeedAge>
    : never;

  // setAge is ONLY available when State is NeedAge
  setAge: State extends NeedAge
    ? (age: number) => Builder<Ready>
    : never;

  // build is ONLY available when State is Ready
  build: State extends Ready
    ? () => Person
    : never;
}

/**
 * The Builder type: only methods matching the current State
 * appear as callable. All others resolve to `never` and
 * produce compile errors if accessed.
 */
type Builder<State> = {
  [K in keyof BuilderMethods<State> as
    BuilderMethods<State>[K] extends never ? never : K
  ]: BuilderMethods<State>[K];
};

// ---------- Runtime implementation ----------

function createBuilder(): Builder<NeedName> {
  // Internal mutable data accumulator
  const data: Partial<Person> = {};

  // We build a single object with all methods, but TypeScript
  // only exposes the ones matching the current phantom state.
  const instance = {
    setName(name: string): Builder<NeedAge> {
      data.name = name;
      return instance as unknown as Builder<NeedAge>;
    },
    setAge(age: number): Builder<Ready> {
      data.age = age;
      return instance as unknown as Builder<Ready>;
    },
    build(): Person {
      return { name: data.name!, age: data.age! };
    },
  };

  return instance as Builder<NeedName>;
}

// ---------- Compile-time verification tests ----------

// ✅ VALID: correct order — setName → setAge → build
const person1: Person = createBuilder()
  .setName('Alice')
  .setAge(30)
  .build();

console.log(person1);
// → { name: "Alice", age: 30 }

// ❌ COMPILE ERROR: setAge doesn't exist on Builder<NeedName>
//    Must call setName first!
// @ts-expect-error
const person2 = createBuilder().setAge(25).setName('Bob').build();

