## Part 2: Ordered Builder Pattern

```typescript
// ============================================================
// BUILDER STATE TRACKING VIA PHANTOM TYPES
// ============================================================

/**
 * Tracks which steps have been completed.
 * Using a record of boolean literals as a "state machine".
 */
interface BuilderState {
  hasName: boolean;
  hasAge: boolean;
}

/** Initial state — nothing set */
type InitialState = { hasName: false; hasAge: false };

/** State after setName */
type NameSet = { hasName: true; hasAge: false };

/** State after setAge (must come after setName) */
type AgeSet = { hasName: true; hasAge: true };

// ============================================================
// CONDITIONAL METHOD AVAILABILITY
// ============================================================

/**
 * The core builder interface.
 * Methods are only present when the state allows them.
 *
 * State machine:
 *   Initial → [setName allowed]
 *   NameSet → [setAge allowed]
 *   AgeSet  → [build allowed]
 */
interface Builder<State extends BuilderState> {
  // setName is only available when name has NOT been set yet
  setName: State["hasName"] extends false
    ? (name: string) => Builder<{ hasName: true; hasAge: State["hasAge"] }>
    : never;

  // setAge is only available AFTER setName (hasName = true, hasAge = false)
  setAge: State extends NameSet
    ? (age: number) => Builder<AgeSet>
    : never;

  // build is only available when BOTH name and age are set
  build: State extends AgeSet ? () => Person : never;
}

interface Person {
  name: string;
  age: number;
}

// ============================================================
// IMPLEMENTATION
// ============================================================

/**
 * Internal mutable accumulator — hidden from the typed interface.
 */
function createBuilder(): Builder<InitialState> {
  const data: Partial<Person> = {};

  // We cast to `any` internally so we can implement all methods
  // while the external API enforces ordering via phantom types.
  const builder: any = {
    setName(name: string) {
      data.name = name;
      return builder;
    },
    setAge(age: number) {
      data.age = age;
      return builder;
    },
    build(): Person {
      if (!data.name || data.age === undefined) {
        throw new Error("Builder state corrupted — this should not happen");
      }
      return { name: data.name, age: data.age };
    },
  };

  return builder as Builder<InitialState>;
}

// ============================================================
// USAGE EXAMPLES
// ============================================================

// ✅ Correct order: setName → setAge → build
const person = createBuilder()
  .setName("Alice")  // Builder<NameSet>
  .setAge(30)        // Builder<AgeSet>
  .build();          // Person

console.log(person); // { name: 'Alice', age: 30 }

// ❌ Compile Error: setAge before setName
// createBuilder()
//   .setAge(30)    // Property 'setAge' is of type 'never'
//   .setName('x')
//   .build();

// ❌ Compile Error: build without setAge
// createBuilder()
//   .setName('Alice')
//   .build();       // Property 'build' is of type 'never'

// ❌ Compile Error: calling setName twice
// createBuilder()
//   .setName('Alice')
//   .setName('Bob')  // Property 'setName' is of type 'never'
//   .setAge(30)
//   .build();

// ❌ Compile Error: skipping setName entirely
// createBuilder().build(); // Property 'build' is of type 'never'
```

