### 2. Builder Pattern with Strict Call Order

```ts
type BuilderState = 'empty' | 'name' | 'complete';

class Builder<T extends BuilderState = 'empty'> {
  private name?: string;
  private age?: number;

  setName(name: string): Builder<'name'> {
    this.name = name;
    return this as any;
  }

  setAge(age: number): Builder<'complete'> {
    if ('name' in (this as any)) {
      this.age = age;
      return this as any;
    }
    throw new Error('Name must be set before age');
  }

  build(): { name: string; age: number } {
    if (!this.name || this.age === undefined) {
      throw new Error('Both name and age must be set');
    }
    return { name: this.name, age: this.age };
  }
}

// Factory function to start the chain
function createBuilder(): Builder<'empty'> {
  return new Builder<'empty'>();
}

// Example usage:
const result = createBuilder()
  .setName('Alice')
  .setAge(30)
  .build(); 
// ✓ OK - returns { name: string; age: number }

// These will cause compile-time errors:
createBuilder()
  .setAge(25)           // ✗ Cannot call setAge before setName
  .setName('Bob')
  .build();

createBuilder()
  .setName('Bob')
  .build();             // ✗ Missing setAge call

createBuilder()
  .setName('Bob')
  .setAge(25)
  .setName('Alice');    // ✗ Cannot call setName after setAge
```

### Alternative: More Type-Safe Builder using Branded Types

For even stricter enforcement without `any`:

```ts
type Brand<K, T> = K & { __brand: T };

type Empty = Brand<{}, 'empty'>;
type HasName = Brand<{}, 'hasName'>;
type Complete = Brand<{}, 'complete'>;

class StrictBuilder<S = Empty> {
  private data: { name?: string; age?: number } = {};

  setName(name: string): StrictBuilder<HasName> {
    this.data.name = name;
    return this as unknown as StrictBuilder<HasName>;
  }

  setAge(age: number): S extends HasName ? StrictBuilder<Complete> : never {
    if (!(this as any) instanceof StrictBuilder || !('data' in this)) {
      throw new Error('Name must be set first');
    }
    this.data.age = age;
    return this as any;
  }

  build(): S extends Complete ? { name: string; age: number } : never {
    if (!this.data.name || this.data.age === undefined) {
      throw new Error('Builder not complete');
    }
    return this.data as any;
  }
}

const strictBuilder = () => new StrictBuilder<Empty>();
```

**Usage:**
```ts
strictBuilder()
  .setName("John")
  .setAge(35)
  .build(); // ✓ Perfect
```

