### 2. Sequential Builder Pattern
We enforce order by returning different interfaces at each step. By using specific return types, we "unlock" the next method in the sequence and hide the previous ones.

```typescript
interface IBuilderFinal {
  build(): { name: string; age: number };
}

interface IBuilderAge {
  setAge(age: number): IBuilderFinal;
}

interface IBuilderName {
  setName(name: string): IBuilderAge;
}

class SequentialBuilder implements IBuilderName, IBuilderAge, IBuilderFinal {
  private name!: string;
  private age!: number;

  setName(name: string): IBuilderAge {
    this.name = name;
    return this;
  }

  setAge(age: number): IBuilderFinal {
    this.age = age;
    return this;
  }

  build() {
    return { name: this.name, age: this.age };
  }
}

const builder: IBuilderName = new SequentialBuilder();

// --- Usage ---
// ✓ Success: Correct order
builder.setName('Alice').setAge(30).build();

// ✗ Error: setAge is not available on IBuilderName (must call setName first)
// @ts-expect-error
builder.setAge(30).setName('Alice').build();

// ✗ Error: build is not available on IBuilderAge (must call setAge first)
// @ts-expect-error
builder.setName('Alice').build();
```

### Explanation of the Techniques:

1.  **Template Literal Types (`ExtractRouteParams`):**
    *   `infer` allows the TypeScript compiler to "reach into" the string literal.
    *   The recursive logic splits the string by `/` and checks if a segment starts with `:`.
    *   If no params are found, it returns `Record<string, never>` to prevent any keys from being passed.

2.  **Interface Chaining (Builder):**
    *   Instead of returning `this` (which contains all methods), we return a specific Interface that only exposes the **next valid step**.
    *   This creates a "Finite State Machine" at the type level. The user cannot skip `setAge` because the object returned by `setName` simply doesn't have a `.build()` method.

```typescript
// ============================================================
// 1. Route Type: URL Template Params vs Params Object
// ============================================================

/**
 * Extracts parameter names from a URL template string.
 * E.g., ExtractRouteParams<"/users/:userId/posts/:postId"> => "userId" | "postId"
 */
type ExtractRouteParams<T extends string> =
  T extends `${string}:${infer Param}/${infer Rest}`
    ? Param | ExtractRouteParams<Rest>
    : T extends `${string}:${infer Param}`
      ? Param
      : never;

/**
 * Creates a strongly-typed route builder.
 *
 * @param template - The URL path containing :param placeholders
 * @param params - An object where keys must match the extracted param names
 */
export function createRoute<
  T extends string,
  P extends Record<ExtractRouteParams<T>, string>
>(template: T, params: P): string {
  let url = template;
  (Object.keys(params) as (keyof P)[]).forEach((key) => {
    url = url.replace(`:${String(key)}`, params[key as keyof P]);
  });
  return url;
}

// --- Examples for Route ---

// ✅ Valid: All params present
const route1 = createRoute('/users/:userId/posts/:postId', {
  userId: '123',
  postId: '456',
});

// ❌ Compile Error: 'wrongParam' does not exist in type '{ userId: string; postId: string; }'
// const route2 = createRoute('/users/:userId/posts/:postId', {
//   wrongParam: '123'
// });

// ❌ Compile Error: 'userId' is missing
// const route3 = createRoute('/users/:userId/posts/:postId', {
//   postId: '456'
// });

// ✅ Valid: No params in template, empty object allowed
const route4 = createRoute('/home', {});


// ============================================================
// 2. Builder Pattern: Enforced Method Order
// ============================================================

// --- State Tokens (Brands) ---
// These represent the "state" of the builder. 
// We use unique symbols or string literals to make them distinct.
type Step1_NameSet = { readonly _step: 'name_set' };
type Step2_AgeSet = { readonly _step: 'age_set' };
type ReadyToBuild = { readonly _step: 'ready' };

// --- The Builder Class ---
// We use generic state `S` to track the progression.
class Builder<S = {}> {
  private nameValue: string = '';
  private ageValue: number = 0;

  // 1. Must be called first (or at least before setAge)
  setName(name: string): Builder<Step1_NameSet> {
    this.nameValue = name;
    // We cast to the next state. 
    // Note: In a real implementation, you might want to prevent calling setName twice,
    // but typically "First" implies the first of the sequence, not strictly "only once".
    return this as unknown as Builder<Step1_NameSet>;
  }

  // 2. Can only be called after setName
  // Constraint: S must be Step1_NameSet
  setAge(this: Builder<Step1_NameSet>, age: number): Builder<Step2_AgeSet> {
    this.ageValue = age;
    return this as unknown as Builder<Step2_AgeSet>;
  }

  // 3. Can only be called after setAge
  // Constraint: S must be Step2_AgeSet
  build(this: Builder<Step2_AgeSet>): { name: string; age: number } {
    return { name: this.nameValue, age: this.ageValue };
  }
}

// --- Examples for Builder ---

// ✅ Valid: Correct Order
const user1 = new Builder()
  .setName('Alice')
  .setAge(30)
  .build();

// ❌ Compile Error: setAge called before setName
// Type 'Builder<{}>' is missing the following properties from type 'Builder<Step1_NameSet>': setName, setAge
// const user2 = new Builder()
//   .setAge(25)
//   .setName('Bob')
//   .build();

// ❌ Compile Error: build called before setAge
// Type 'Builder<Step1_NameSet>' is missing the following properties from type 'Builder<Step2_AgeSet>': setAge, build
